                    <span key={e.id} className="px-3 py-1 rounded-full text-xs font-semibold bg-indigo-100 text-indigo-800 border border-indigo-200 flex items-center">
                       <ChefHatIcon className="w-3 h-3 mr-1"/> {e.name}
                    </span>
                ))}
            </div>
        );
    };

