                                    {COURSE_MODULES.map(mod => {
                                        const isSostenibilidad = mod.name === 'Sostenibilidad aplicada al sistema productivo';
                                        const isConvalidated = allCourseGrades[student.id]?.[mod.name]?.isConvalidated;

