                                 </tr>
                             </thead>
                             <tbody>
                                 {GROUP_EVALUATION_ITEMS.map((item, itemIndex) => (<tr key={item.id}><td className="p-2 border text-left">{item.label}</td>{evaluationUnits.map(unit => {const groupEval = evaluation.serviceDay.groupScores[unit.id]; return (<td key={unit.id} className="p-1 border align-middle"><input type="number" step="0.1" min="0" max={item.maxScore} value={groupEval?.scores[itemIndex] ?? ''} onChange={e => handleNumericInputChange(e, item.maxScore, (value) => {
                                     // FIX: Explicitly type draft as any to prevent indexing errors.
                                     deepCloneAndUpdate((draft: any) => {if (!draft.serviceDay.groupScores[unit.id]) draft.serviceDay.groupScores[unit.id] = { scores: Array(GROUP_EVALUATION_ITEMS.length).fill(null), observations: ''}; draft.serviceDay.groupScores[unit.id]!.scores[itemIndex] = value;})})} placeholder={`max: ${item.maxScore.toFixed(2)}`} className="w-full text-center p-1.5 rounded-md border-gray-300 placeholder-gray-300 disabled:bg-gray-100" disabled={isLocked}/></td>)})}</tr>))}
                             </tbody>
                             <tfoot>
                                 <tr className="bg-gray-100 font-bold">
                                     <td className="p-2 border text-left">TOTAL</td>
                                     {evaluationUnits.map(unit => { 
                                         const scores = (evaluation.serviceDay.groupScores[unit.id]?.scores?.filter(s => s !== null) as number[]) ?? []; 
                                         const total = scores.reduce((sum, s) => sum + (s || 0), 0); 
                                         return <td key={unit.id} className="p-2 border text-center">{total.toFixed(2)} / {GROUP_EVALUATION_ITEMS.reduce((acc, item) => acc + item.maxScore, 0).toFixed(2)}</td>
                                     })}
                                 </tr>
                                 <tr>
                                    <td className="p-2 border text-left font-medium">Observaciones</td>
                                    {evaluationUnits.map(unit => (<td key={unit.id} className="p-1 border"><textarea value={evaluation.serviceDay.groupScores[unit.id]?.observations || ''} onChange={e => { 
                                        // FIX: Explicitly type draft as any to prevent indexing errors.
                                        deepCloneAndUpdate((draft: any) => { if (!draft.serviceDay.groupScores[unit.id]) { draft.serviceDay.groupScores[unit.id] = { scores: Array(GROUP_EVALUATION_ITEMS.length).fill(null), observations: '' }; } draft.serviceDay.groupScores[unit.id]!.observations = e.target.value; }); }} className="w-full h-20 p-1 rounded-md border-gray-200 resize-none disabled:bg-gray-100" placeholder="Anotaciones..." disabled={isLocked}/></td>))}
                                </tr>
                             </tfoot>
                         </table>
                    </div>

                    {evaluationUnits.map(unit => {
                        if(unit.students.length === 0) return null;
                        return(
                            <div key={unit.id} className="bg-white p-4 rounded-lg shadow-sm">
                                <h3 className="text-xl font-bold mb-1 text-gray-700">Evaluación Individual - {unit.name}</h3>
                                {renderAssignedDishes(unit.id)}
                                <ServiceDayIndividualEvaluationTable 
                                    studentsInGroup={unit.students} 
                                    evaluationData={evaluation.serviceDay.individualScores} 
                                    onUpdate={handleServiceDayIndividualUpdate} 
                                    handleNumericInputChange={handleNumericInputChange} 
                                    entryExitRecordsForWeek={entryExitRecordsForWeek} 
                                    isLocked={isLocked}
                                    service={service}
                                    serviceRoles={serviceRoles}
                                />
                            </div>
                        )
                    })}
                 </div>
            )}
        </div>
    );
};

